from typing import List

class Solution:
    def shipWithinDays(self, weights: List[int], days: int) -> int:
        def can_ship(capacity: int) -> bool:
            cur_load, cur_days = 0, 1
            for w in weights:
                if cur_load + w > capacity:
                    cur_days += 1
                    cur_load = w
                else:
                    cur_load += w
            return cur_days <= days

        left, right = max(weights), sum(weights)
        while left < right:
            mid = (left + right) // 2
            if can_ship(mid):
                right = mid
            else:
                left = mid + 1
        return left
